#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long
using namespace std;
const int N=5e4+10;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
int mu[N],pm[N>>2],cnt,Cnt[N];bool vs[N];
inline int CNT(int n)
{
	int ans=0;for(int l=1,r=0;l<=n;l=r+1)
		{r=n/(n/l);ans+=(r-l+1)*(n/l);} return ans;
}
inline void Init(int mx)
{
	vs[1]=mu[1]=1;rep(2,mx,i)
	{
		if(!vs[i])mu[pm[++cnt]=i]=-1;rep(1,cnt,j)
		{
			if(pm[j]*i>mx)break;
			mu[pm[j]*i]=(i%pm[j]==0?0:-mu[i]);
			vs[pm[j]*i]=1;if(i%pm[j]==0)break;
		}
	}
	rep(1,mx,i)mu[i]+=mu[i-1],Cnt[i]=CNT(i);
}

inline void Solve()
{
	int n=read(),m=read(),ans=0;if(n>m)swap(n,m);
	for(int l=1,r=0;l<=n;l=r+1)
	{
		r=min(n/(n/l),m/(m/l));
		ans+=(mu[r]-mu[l-1])*Cnt[n/l]*Cnt[m/l];
	}
	printf("%ld\n",ans);return;
}
signed main(){Init(N-10);int T=read();while(T--)Solve();return 0;}
